let elCatNav, elToolGrid, elSearchInput, elResultMeta, elEmptyState,
    elSearchClear, elProfilePanel, elFavPanel, elOverlay,
    elProfileList, elProfileListSection, elProfileFormSection,
    elProfileFormTitle, elFavList;

let activeTheme = 'dark';
let activeProfileImageData = '';

function refreshIcons() {
  if (window.lucide && typeof window.lucide.createIcons === 'function') {
    window.lucide.createIcons();
  }
}

function getPreferredTheme() {
  try {
    const saved = localStorage.getItem(THEME_STORAGE_KEY);
    if (saved === 'light' || saved === 'dark') return saved;
  } catch (e) { /* ignore */ }

  if (window.matchMedia && window.matchMedia('(prefers-color-scheme: light)').matches) {
    return 'light';
  }
  return 'dark';
}

function updateThemeToggleButton() {
  const btn = document.getElementById('themeToggleBtn');
  if (!btn) return;
  const iconName = activeTheme === 'dark' ? 'sun' : 'moon';
  btn.classList.toggle('theme-dark', activeTheme === 'dark');
  btn.classList.toggle('theme-light', activeTheme === 'light');
  btn.innerHTML = `
    <span class="btn-icon" aria-hidden="true"><i data-lucide="${iconName}"></i></span>
    <span class="btn-label">Theme</span>
  `;
  refreshIcons();
}

function setTheme(theme, persist = true) {
  activeTheme = theme === 'light' ? 'light' : 'dark';
  document.documentElement.setAttribute('data-theme', activeTheme);
  if (persist) {
    try { localStorage.setItem(THEME_STORAGE_KEY, activeTheme); } catch (e) { /* ignore */ }
  }
  updateThemeToggleButton();
}

// ── Sidebar: Render Categories ────────────────────────────────────────────────
function renderSidebar() {
  elCatNav.innerHTML = '';

  // "All" item
  const allBtn = makeCatItem('all', '★ All Tools', getTotalToolCount(), true);
  elCatNav.appendChild(allBtn);

  // "Favorites" item
  const favBtn = makeCatItem('favorites', '★ Favorites', appState.favorites.length, false, true);
  elCatNav.appendChild(favBtn);

  // Category items
  osintData.forEach(group => {
    const item = makeCatItem(group.category, group.category, group.tools.length);
    elCatNav.appendChild(item);
  });
}

function makeCatItem(key, label, count, isAll = false, isFav = false) {
  const el = document.createElement('div');
  el.className = 'cat-item' + (isAll ? ' all-item' : '') + (isFav ? ' fav-item' : '') + (activeCategory === key ? ' active' : '');
  el.innerHTML = `<span class="cat-name">${escHtml(label)}</span><span class="cat-count">${count}</span>`;
  el.addEventListener('click', () => {
    activeCategory = key;
    searchQuery = '';
    elSearchInput.value = '';
    elSearchClear.classList.add('hidden');
    renderSidebar();
    renderGrid();
  });
  return el;
}

function getTotalToolCount() {
  return osintData.reduce((s, g) => s + g.tools.length, 0);
}

// ── Tool Grid: Render Tools ───────────────────────────────────────────────────
function renderGrid() {
  elToolGrid.innerHTML = '';
  elEmptyState.classList.add('hidden');

  const q = searchQuery.trim().toLowerCase();
  let rendered = 0;

  if (activeCategory === 'favorites') {
    const favSet = new Set(appState.favorites.map(f => f.url));
    const favTools = [];
    osintData.forEach(group => {
      group.tools.forEach(tool => {
        if (favSet.has(tool.url)) {
          favTools.push({ tool, category: group.category });
        }
      });
    });

    const filtered = favTools.filter(({ tool, category }) => matchesSearch(tool, q) && matchesReq(tool) && matchesFacet(tool, category) && matchesRegion(tool, category) && matchesSafety(tool));
    filtered.forEach(({ tool, category }) => {
      elToolGrid.appendChild(makeToolCard(tool, category));
      rendered++;
    });

  } else if (activeCategory === 'all') {
    osintData.forEach(group => {
      const matchingTools = group.tools.filter(t => matchesSearch(t, q) && matchesReq(t) && matchesFacet(t, group.category) && matchesRegion(t, group.category) && matchesSafety(t));
      if (matchingTools.length === 0) return;

      if (!q && activeReqFilter === 'all' && activeFacetFilter === 'all' && activeRegionFilter === 'all' && activeSafetyFilter === 'all') {
        // Show category header in "all" view
        const hdr = document.createElement('div');
        hdr.className = 'cat-section-title';
        hdr.innerHTML = `<h2>${escHtml(group.category)}</h2><span>${matchingTools.length} tools</span>`;
        elToolGrid.appendChild(hdr);
      }

      matchingTools.forEach(tool => {
        elToolGrid.appendChild(makeToolCard(tool, group.category));
        rendered++;
      });
    });

  } else {
    const group = osintData.find(g => g.category === activeCategory);
    if (group) {
      const matchingTools = group.tools.filter(t => matchesSearch(t, q) && matchesReq(t) && matchesFacet(t, group.category) && matchesRegion(t, group.category) && matchesSafety(t));
      matchingTools.forEach(tool => {
        elToolGrid.appendChild(makeToolCard(tool, group.category));
        rendered++;
      });
    }
  }

  // Update result meta
  const total = getTotalToolCount();
  if (q || activeReqFilter !== 'all' || activeFacetFilter !== 'all' || activeRegionFilter !== 'all' || activeSafetyFilter !== 'all') {
    elResultMeta.textContent = `${rendered.toLocaleString()} result${rendered !== 1 ? 's' : ''}`;
  } else if (activeCategory === 'all') {
    elResultMeta.textContent = `${total.toLocaleString()} tools across ${osintData.length} categories`;
  } else if (activeCategory === 'favorites') {
    elResultMeta.textContent = `${rendered.toLocaleString()} favorite${rendered !== 1 ? 's' : ''}`;
  } else {
    elResultMeta.textContent = `${rendered.toLocaleString()} tool${rendered !== 1 ? 's' : ''}`;
  }

  // Show empty state
  if (rendered === 0) {
    elEmptyState.classList.remove('hidden');
  }

  refreshIcons();
}

function matchesSearch(tool, q) {
  if (!q) return true;
  return tool.name.toLowerCase().includes(q) ||
    (tool.desc && tool.desc.toLowerCase().includes(q)) ||
    (tool.url && tool.url.toLowerCase().includes(q));
}

function matchesReq(tool) {
  if (activeReqFilter === 'all') return true;
  return getToolTags(tool).includes(activeReqFilter);
}

function matchesFacet(tool, category) {
  if (activeFacetFilter === 'all') return true;
  return getToolFacets(tool, category).includes(activeFacetFilter);
}

function matchesRegion(tool, category) {
  if (activeRegionFilter === 'all') return true;
  return getToolRegions(tool, category).includes(activeRegionFilter);
}

function matchesSafety(tool) {
  if (activeSafetyFilter === 'all') return true;
  return getToolSafety(tool) === activeSafetyFilter;
}

function getToolFacets(tool, category) {
  const facets = new Set();
  const url = (tool.url || '').toLowerCase();
  const desc = (tool.desc || '').toLowerCase();
  const categoryName = (category || '').toLowerCase();

  if (categoryName.includes('people') || categoryName.includes('dating') || categoryName.includes('telephone') || categoryName.includes('public records') || categoryName.includes('username') || categoryName.includes('social networks') || categoryName.includes('instant messaging') || categoryName.includes('breach & leak intelligence')) {
    facets.add('people');
  }

  if (categoryName.includes('cloud infrastructure') || categoryName.includes('domain name') || categoryName.includes('ip & mac') || categoryName.includes('cyber threat intelligence') || categoryName.includes('web capture & surface analysis')) {
    facets.add('infra');
  }

  if (categoryName.includes('images / videos / docs') || categoryName.includes('geolocation tools / maps') || categoryName.includes('disinformation & media verification') || categoryName.includes('metadata & file analysis')) {
    facets.add('media');
  }

  if (url.includes('github.com') || url.includes('gitlab.com') || url.includes('codeberg.org') || url.includes('sourcegraph.com') || url.includes('grep.app') || url.includes('searchcode.com')) {
    facets.add('repo');
  }

  if (url.includes('.gov') || url.includes('.mil') || url.includes('europa.eu') || url.includes('govinfo.gov') || url.includes('sam.gov') || url.includes('courtlistener.com') || categoryName.includes('government, court & sanctions')) {
    facets.add('government');
  }

  if (url.includes('data.gov') || url.includes('worldbank.org') || url.includes('openalex.org') || url.includes('gdeltproject.org') || url.includes('dbpedia.org') || url.includes('wikidata.org') || url.includes('zenodo.org') || url.includes('kaggle.com/datasets') || categoryName.includes('datasets & knowledge bases') || desc.includes('dataset')) {
    facets.add('dataset');
  }

  return Array.from(facets);
}

function getHostname(rawUrl) {
  try {
    return new URL(rawUrl).hostname.toLowerCase();
  } catch {
    return '';
  }
}

function getToolOverride(tool) {
  const host = getHostname(tool.url || '');
  const name = (tool.name || '').trim();
  return TOOL_OVERRIDE_RULES.find(rule => {
    const hostMatch = rule.host ? host === rule.host || host.endsWith(`.${rule.host}`) : true;
    const nameMatch = rule.name ? rule.name === name : true;
    return hostMatch && nameMatch;
  }) || null;
}

function normalizeTags(tags) {
  const normalized = Array.isArray(tags)
    ? tags.map(t => String(t).toLowerCase()).filter(t => TAG_WHITELIST.has(t))
    : [];
  return normalized.length ? Array.from(new Set(normalized)) : ['open'];
}

function isRepoHost(host) {
  return Array.from(REPO_HOSTS).some(base => host === base || host.endsWith(`.${base}`));
}

function isGovLikeHost(host) {
  return GOV_LIKE_HOST_SUFFIXES.some(sfx => host === sfx || host.endsWith(`.${sfx}`));
}

function applyHostTagCorrections(tool, tags) {
  const host = getHostname(tool.url || '');
  const corrected = new Set(tags);

  if (isRepoHost(host)) {
    corrected.delete('paid');
    corrected.delete('login');
    corrected.delete('api');
    corrected.add('install');
  }

  if (isGovLikeHost(host)) {
    corrected.delete('paid');
  }

  if (!corrected.size) {
    corrected.add('open');
  }

  return Array.from(corrected).filter(t => TAG_WHITELIST.has(t));
}

function getToolTags(tool) {
  const override = getToolOverride(tool);
  if (override && override.tags) {
    return normalizeTags(override.tags);
  }
  return applyHostTagCorrections(tool, normalizeTags(tool.tags));
}

function hostEndsWith(rawUrl, suffix) {
  const host = getHostname(rawUrl);
  return host === suffix || host.endsWith(`.${suffix}`);
}

function getToolRegions(tool, category) {
  const override = getToolOverride(tool);
  if (override && Array.isArray(override.regions) && override.regions.length) {
    const base = Array.from(new Set(override.regions.map(r => String(r).toLowerCase())));
    return base.length > 1 ? Array.from(new Set([...base, 'regional'])) : base;
  }

  const regions = new Set();
  const categoryName = (category || '').toLowerCase();
  const host = getHostname(tool.url || '');

  const addRegional = code => {
    regions.add(code);
    regions.add('regional');
  };

  if (host === 'gov.uk' || host.endsWith('.gov.uk') || host.endsWith('.co.uk') || host.endsWith('.uk')) {
    addRegional('uk');
  }

  if (host === 'gc.ca' || host.endsWith('.gc.ca') || host.endsWith('.ca')) {
    addRegional('ca');
  }

  if (host === 'gov.au' || host.endsWith('.gov.au') || host.endsWith('.au')) {
    addRegional('au');
  }

  if (host.endsWith('.de')) {
    addRegional('de');
  }

  if (host.endsWith('.nl')) {
    addRegional('nl');
  }

  if (host.endsWith('.in')) {
    addRegional('in');
  }

  if (host.endsWith('.gov') || host.endsWith('.mil') || host.endsWith('.us') || host.endsWith('.edu')) {
    addRegional('us');
  }

  if (host === 'europa.eu' || host.endsWith('.europa.eu') || host.endsWith('.eu')) {
    addRegional('eu');
  }

  if (GLOBAL_HOST_HINTS.has(host) || Array.from(GLOBAL_HOST_HINTS).some(base => host.endsWith(`.${base}`))) {
    regions.add('global');
  }

  // Category-level conservative rule: training and open datasets are often global-facing.
  if (categoryName.includes('training') || categoryName.includes('datasets')) {
    regions.add('global');
  }

  if (!regions.size) {
    regions.add('regional');
  }

  return Array.from(regions);
}

function getDisplayRegions(tool, category) {
  const regions = getToolRegions(tool, category).filter(region => region !== 'regional');
  return regions.length ? regions : ['regional'];
}

function regionLabel(region) {
  return {
    global: 'Global',
    us: 'US',
    uk: 'UK',
    eu: 'EU',
    ca: 'CA',
    in: 'IN',
    de: 'DE',
    nl: 'NL',
    au: 'AU',
    regional: 'Regional'
  }[region] || region.toUpperCase();
}

function getToolSafety(tool) {
  const override = getToolOverride(tool);
  if (override && override.safety) {
    return override.safety;
  }

  const url = (tool.url || '').toLowerCase();
  const name = (tool.name || '').trim();

  if (!/^https?:\/\//.test(url)) return 'caution';
  if (url.startsWith('http://')) return 'caution';
  if (KNOWN_CAUTION_TOOL_NAMES.has(name)) return 'caution';
  return 'screened';
}

function safetyLabel(level) {
  return level === 'caution' ? 'Caution' : 'Screened';
}

function makeToolCard(tool, category) {
  const isFav = appState.favorites.some(f => f.url === tool.url);
  const card = document.createElement('div');
  card.className = 'tool-card';

  const badges = getToolTags(tool).map(t =>
    `<span class="req-badge ${t}">${badgeLabel(t)}</span>`
  ).join('');

  const descHtml = tool.desc
    ? `<div class="card-desc">${escHtml(tool.desc)}</div>`
    : '';

  const regionBadges = getDisplayRegions(tool, category)
    .map(region => `<span class="meta-badge region">${regionLabel(region)}</span>`)
    .join('');
  const safety = getToolSafety(tool);
  const signalBadges = `${regionBadges}<span class="meta-badge safety ${safety}">${safetyLabel(safety)}</span>`;

  // Show category label only in All or Favorites view
  const catLabel = (activeCategory === 'all' || activeCategory === 'favorites')
    ? `<div class="card-category">${escHtml(category)}</div>`
    : '';

  card.innerHTML = `
    <div class="card-top">
      <div class="card-title"><a href="${escHtml(tool.url)}" target="_blank" rel="noopener noreferrer" title="${escHtml(tool.name)}">${escHtml(tool.name)}</a></div>
      <button class="card-fav${isFav ? ' pinned' : ''}" data-url="${escHtml(tool.url)}" aria-label="${isFav ? 'Unpin' : 'Pin'} ${escHtml(tool.name)}"><i data-lucide="star"></i></button>
    </div>
    <div class="card-badges">${badges}</div>
    <div class="card-signals">${signalBadges}</div>
    ${descHtml}
    ${catLabel}
  `;

  card.querySelector('.card-fav').addEventListener('click', e => {
    e.stopPropagation();
    toggleFav(tool, category);
    // Re-render the card in place
    const newCard = makeToolCard(tool, category);
    card.replaceWith(newCard);
    renderSidebar();
    renderFavPanel();
    saveState();
    // If in favorites view and unfavorited, remove
    if (activeCategory === 'favorites') renderGrid();
  });

  return card;
}

function badgeLabel(tag) {
  return { open: 'Open', login: 'Login', api: 'API', paid: 'Paid', install: 'Install', dork: 'Dork' }[tag] || tag;
}

function toggleFav(tool, category) {
  const idx = appState.favorites.findIndex(f => f.url === tool.url);
  if (idx >= 0) {
    appState.favorites.splice(idx, 1);
  } else {
    appState.favorites.push({ url: tool.url, name: tool.name, category });
  }
}

// ── Favorites Panel ───────────────────────────────────────────────────────────
function renderFavPanel() {
  elFavList.innerHTML = '';
  if (appState.favorites.length === 0) {
    elFavList.innerHTML = '<div class="empty-fav">No favorites yet. Click the star on any tool to pin it here.</div>';
    refreshIcons();
    return;
  }
  appState.favorites.forEach(fav => {
    const item = document.createElement('div');
    item.className = 'fav-list-item';
    item.innerHTML = `
      <div class="fav-item-name"><a href="${escHtml(fav.url)}" target="_blank" rel="noopener noreferrer">${escHtml(fav.name)}</a></div>
      <div class="fav-item-cat">${escHtml(fav.category)}</div>
      <button class="fav-unpin" data-url="${escHtml(fav.url)}" title="Remove favorite" aria-label="Remove favorite"><i data-lucide="x"></i></button>
    `;
    item.querySelector('.fav-unpin').addEventListener('click', () => {
      const idx = appState.favorites.findIndex(f => f.url === fav.url);
      if (idx >= 0) appState.favorites.splice(idx, 1);
      saveState();
      renderFavPanel();
      renderSidebar();
      if (activeCategory === 'favorites') renderGrid();
    });
    elFavList.appendChild(item);
  });

  refreshIcons();
}

// ── Profile Panel ─────────────────────────────────────────────────────────────
function showProfilePanel() {
  elProfilePanel.classList.remove('hidden');
  elFavPanel.classList.add('hidden');
  elOverlay.classList.remove('hidden');
  document.getElementById('profilesToggleBtn').classList.add('active');
  document.getElementById('favToggleBtn').classList.remove('active');
}

function hideProfilePanel() {
  elProfilePanel.classList.add('hidden');
  elOverlay.classList.add('hidden');
  document.getElementById('profilesToggleBtn').classList.remove('active');
}

function showFavPanel() {
  elFavPanel.classList.remove('hidden');
  elProfilePanel.classList.add('hidden');
  elOverlay.classList.remove('hidden');
  document.getElementById('favToggleBtn').classList.add('active');
  document.getElementById('profilesToggleBtn').classList.remove('active');
  renderFavPanel();
}

function hideFavPanel() {
  elFavPanel.classList.add('hidden');
  elOverlay.classList.add('hidden');
  document.getElementById('favToggleBtn').classList.remove('active');
}

// ── Profile CRUD ──────────────────────────────────────────────────────────────
function renderProfileList() {
  elProfileList.innerHTML = '';
  if (appState.profiles.length === 0) {
    elProfileList.innerHTML = '<div class="empty-fav">No profiles saved yet.</div>';
    return;
  }
  appState.profiles.forEach(profile => {
    const item = document.createElement('div');
    item.className = 'profile-item';
    item.setAttribute('draggable', 'true');
    item.innerHTML = `
      <div class="profile-item-top">
        ${getProfileAvatarMarkup(profile)}
        <div class="profile-item-main">
          <div class="profile-item-name">${escHtml(profile.fullName || profile.alias || 'Unnamed')}</div>
          <div class="profile-item-sub">${escHtml([profile.alias, profile.location, profile.risk].filter(Boolean).join(' · '))}</div>
        </div>
      </div>
      <div class="profile-item-actions">
        <button class="small-btn edit-btn">Edit</button>
        <button class="small-btn delete-btn" style="color:#f85149;border-color:#4a1840;">Delete</button>
      </div>
    `;
    item.querySelector('.edit-btn').addEventListener('click', () => openProfileForm(profile.id));
    item.querySelector('.delete-btn').addEventListener('click', () => {
      if (confirm(`Delete profile "${profile.fullName || profile.alias}"?`)) {
        appState.profiles = appState.profiles.filter(p => p.id !== profile.id);
        saveState();
        renderProfileList();
      }
    });
    elProfileList.appendChild(item);
  });
}

function openProfileForm(profileId) {
  elProfileListSection.classList.add('hidden');
  elProfileFormSection.classList.remove('hidden');
  appState.activeProfileId = profileId || null;

  if (profileId) {
    const p = appState.profiles.find(x => x.id === profileId);
    if (p) {
      elProfileFormTitle.textContent = 'Edit Profile';
      activeProfileImageData = p.imageData || '';
      document.getElementById('pf_fullName').value = p.fullName || '';
      document.getElementById('pf_alias').value = p.alias || '';
      document.getElementById('pf_dob').value = p.dob || '';
      document.getElementById('pf_location').value = p.location || '';
      document.getElementById('pf_emails').value = (p.emails || []).join('\n');
      document.getElementById('pf_phones').value = (p.phones || []).join('\n');
      document.getElementById('pf_usernames').value = (p.usernames || []).join('\n');
      document.getElementById('pf_employers').value = (p.employers || []).join('\n');
      document.getElementById('pf_relationship').value = p.relationship || '';
      document.getElementById('pf_risk').value = p.risk || '';
      document.getElementById('pf_tags').value = (p.tags || []).join(', ');
      document.getElementById('pf_notes').value = p.notes || '';
      document.getElementById('pf_avatarInput').value = '';
      updateProfileAvatarPreview();
    }
  } else {
    elProfileFormTitle.textContent = 'New Profile';
    document.getElementById('profileForm').reset();
    activeProfileImageData = '';
    document.getElementById('pf_avatarInput').value = '';
    updateProfileAvatarPreview();
  }
}

function saveProfile() {
  const id = appState.activeProfileId || ('p' + Date.now());
  const profile = {
    id,
    imageData: activeProfileImageData || '',
    fullName: document.getElementById('pf_fullName').value.trim(),
    alias: document.getElementById('pf_alias').value.trim(),
    dob: document.getElementById('pf_dob').value.trim(),
    location: document.getElementById('pf_location').value.trim(),
    emails: document.getElementById('pf_emails').value.split('\n').map(s => s.trim()).filter(Boolean),
    phones: document.getElementById('pf_phones').value.split('\n').map(s => s.trim()).filter(Boolean),
    usernames: document.getElementById('pf_usernames').value.split('\n').map(s => s.trim()).filter(Boolean),
    employers: document.getElementById('pf_employers').value.split('\n').map(s => s.trim()).filter(Boolean),
    relationship: document.getElementById('pf_relationship').value.trim(),
    risk: document.getElementById('pf_risk').value,
    tags: document.getElementById('pf_tags').value.split(',').map(s => s.trim()).filter(Boolean),
    notes: document.getElementById('pf_notes').value.trim(),
    updatedAt: new Date().toISOString()
  };

  if (appState.activeProfileId) {
    const idx = appState.profiles.findIndex(p => p.id === appState.activeProfileId);
    if (idx >= 0) appState.profiles[idx] = profile;
  } else {
    appState.profiles.push(profile);
  }

  appState.activeProfileId = null;
  saveState();
  backToList();
}

function backToList() {
  elProfileFormSection.classList.add('hidden');
  elProfileListSection.classList.remove('hidden');
  appState.activeProfileId = null;
  activeProfileImageData = '';
  document.getElementById('pf_avatarInput').value = '';
  renderProfileList();
}

function getProfileInitial(profile) {
  const source = (profile.fullName || profile.alias || '').trim();
  return source ? source.charAt(0).toUpperCase() : '?';
}

function getProfileAvatarMarkup(profile) {
  if (profile.imageData) {
    return `<div class="profile-avatar" aria-hidden="true"><img src="${escHtml(profile.imageData)}" alt="" /></div>`;
  }
  return `<div class="profile-avatar" aria-hidden="true"><span class="profile-avatar-initial">${escHtml(getProfileInitial(profile))}</span></div>`;
}

function updateProfileAvatarPreview() {
  const preview = document.getElementById('profileAvatarPreview');
  if (!preview) return;

  const name = document.getElementById('pf_fullName')?.value.trim() || document.getElementById('pf_alias')?.value.trim() || '';
  const initial = name ? name.charAt(0).toUpperCase() : '?';
  if (activeProfileImageData) {
    preview.innerHTML = `<img src="${escHtml(activeProfileImageData)}" alt="Selected profile image" />`;
    return;
  }
  preview.innerHTML = `<span class="profile-avatar-initial">${escHtml(initial)}</span>`;
}

// ── Utilities ─────────────────────────────────────────────────────────────────
function escHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ── Export / Import ───────────────────────────────────────────────────────────
function exportProfiles() {
  const data = JSON.stringify(appState.profiles, null, 2);
  const blob = new Blob([data], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `justosinit-profiles-${new Date().toISOString().slice(0,10)}.json`;
  a.click();
}

function importProfiles(file) {
  const reader = new FileReader();
  reader.onload = e => {
    try {
      const parsed = JSON.parse(e.target.result);
      if (!Array.isArray(parsed)) throw new Error('Expected array');
      appState.profiles = parsed;
      saveState();
      renderProfileList();
    } catch {
      alert('Invalid JSON file. Please use a file exported from JustOSINT.');
    }
  };
  reader.readAsText(file);
}

// ── Init ──────────────────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  loadState();
  setTheme(getPreferredTheme(), false);

  // Cache DOM refs
  elCatNav         = document.getElementById('catNav');
  elToolGrid       = document.getElementById('toolGrid');
  elSearchInput    = document.getElementById('searchInput');
  elResultMeta     = document.getElementById('resultMeta');
  elEmptyState     = document.getElementById('emptyState');
  elSearchClear    = document.getElementById('searchClear');
  elProfilePanel   = document.getElementById('profilePanel');
  elFavPanel       = document.getElementById('favPanel');
  elOverlay        = document.getElementById('overlay');
  elProfileList    = document.getElementById('profileList');
  elProfileListSection  = document.getElementById('profileListSection');
  elProfileFormSection  = document.getElementById('profileFormSection');
  elProfileFormTitle    = document.getElementById('profileFormTitle');
  elFavList        = document.getElementById('favList');

  // Initial render
  renderSidebar();
  renderGrid();
  refreshIcons();

  document.getElementById('themeToggleBtn').addEventListener('click', () => {
    const nextTheme = activeTheme === 'dark' ? 'light' : 'dark';
    setTheme(nextTheme, true);
  });

  // ── Search ────────────────────────────────────────────
  elSearchInput.addEventListener('input', () => {
    const val = elSearchInput.value;
    elSearchClear.classList.toggle('hidden', !val);
    clearTimeout(searchDebounce);
    searchDebounce = setTimeout(() => {
      searchQuery = val.trim().toLowerCase();
      renderGrid();
    }, 180);
  });

  document.getElementById('searchClear').addEventListener('click', () => {
    elSearchInput.value = '';
    elSearchClear.classList.add('hidden');
    searchQuery = '';
    renderGrid();
  });

  // ── Req filter buttons ────────────────────────────────
  document.getElementById('reqFilters').addEventListener('click', e => {
    const btn = e.target.closest('.req-filter');
    if (!btn) return;
    activeReqFilter = btn.dataset.req;
    document.querySelectorAll('.req-filter').forEach(b => b.classList.toggle('active', b.dataset.req === activeReqFilter));
    renderGrid();
  });

  document.getElementById('facetFilters').addEventListener('click', e => {
    const btn = e.target.closest('.facet-filter');
    if (!btn) return;
    activeFacetFilter = btn.dataset.facet;
    document.querySelectorAll('.facet-filter').forEach(b => b.classList.toggle('active', b.dataset.facet === activeFacetFilter));
    renderGrid();
  });

  document.getElementById('regionFilters').addEventListener('click', e => {
    const btn = e.target.closest('.region-filter');
    if (!btn) return;
    activeRegionFilter = btn.dataset.region;
    document.querySelectorAll('.region-filter').forEach(b => b.classList.toggle('active', b.dataset.region === activeRegionFilter));
    renderGrid();
  });

  document.getElementById('safetyFilters').addEventListener('click', e => {
    const btn = e.target.closest('.safety-filter');
    if (!btn) return;
    activeSafetyFilter = btn.dataset.safety;
    document.querySelectorAll('.safety-filter').forEach(b => b.classList.toggle('active', b.dataset.safety === activeSafetyFilter));
    renderGrid();
  });

  // ── Profile panel ─────────────────────────────────────
  document.getElementById('profilesToggleBtn').addEventListener('click', () => {
    if (elProfilePanel.classList.contains('hidden')) {
      showProfilePanel();
      renderProfileList();
    } else {
      hideProfilePanel();
      elOverlay.classList.add('hidden');
    }
  });

  document.getElementById('profilePanelClose').addEventListener('click', () => {
    hideProfilePanel();
    elOverlay.classList.add('hidden');
  });

  document.getElementById('newProfileBtn').addEventListener('click', () => openProfileForm(null));
  document.getElementById('backToListBtn').addEventListener('click', backToList);
  document.getElementById('cancelProfileBtn').addEventListener('click', backToList);
  document.getElementById('saveProfileBtn').addEventListener('click', saveProfile);

  document.getElementById('pf_fullName').addEventListener('input', updateProfileAvatarPreview);
  document.getElementById('pf_alias').addEventListener('input', updateProfileAvatarPreview);

  document.getElementById('pf_avatarInput').addEventListener('change', e => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    if (file.size > MAX_PROFILE_IMAGE_BYTES) {
      alert('Image too large. Please select an image under 1MB.');
      e.target.value = '';
      return;
    }

    const reader = new FileReader();
    reader.onload = ev => {
      if (typeof ev.target?.result !== 'string') return;
      activeProfileImageData = ev.target.result;
      updateProfileAvatarPreview();
    };
    reader.onerror = () => alert('Unable to read image file. Please try another image.');
    reader.readAsDataURL(file);
  });

  document.getElementById('pf_avatarClear').addEventListener('click', () => {
    activeProfileImageData = '';
    document.getElementById('pf_avatarInput').value = '';
    updateProfileAvatarPreview();
  });

  document.getElementById('exportProfilesBtn').addEventListener('click', exportProfiles);
  document.getElementById('importProfilesInput').addEventListener('change', e => {
    if (e.target.files[0]) importProfiles(e.target.files[0]);
  });

  // ── Fav panel ─────────────────────────────────────────
  document.getElementById('favToggleBtn').addEventListener('click', () => {
    if (elFavPanel.classList.contains('hidden')) {
      showFavPanel();
    } else {
      hideFavPanel();
      elOverlay.classList.add('hidden');
    }
  });

  document.getElementById('favPanelClose').addEventListener('click', () => {
    hideFavPanel();
    elOverlay.classList.add('hidden');
  });

  // ── Overlay click closes panels ───────────────────────
  elOverlay.addEventListener('click', () => {
    hideProfilePanel();
    hideFavPanel();
    elOverlay.classList.add('hidden');
  });

  // ── Search: hide clear btn initially ─────────────────
  elSearchClear.classList.add('hidden');
  updateProfileAvatarPreview();
});
